using Dungnz.Display; using Dungnz.Engine; using Dungnz.Models; using Dungnz.Systems; using Dungnz.Systems.Enemies; using Dungnz.Tests.Helpers; using FluentAssertions; using Xunit;
namespace Dungnz.Tests;
public class GameLoopIntegrationTests {
    [Fact] public void FullGameLoop_Combat_LootDrop_InventoryIntegration() { var display = new FakeDisplayService(); var input = new FakeInputReader("A"); var player = new Player { Name = "TestHero", HP = 100, MaxHP = 100, Attack = 50, Defense = 10 }; var weakGoblin = new Goblin(); weakGoblin.HP = 1; weakGoblin.Attack = 1; var lootSword = new Item { Name = "Iron Sword", Type = ItemType.Weapon, AttackBonus = 5 }; weakGoblin.LootTable = new LootTable(minGold: 5, maxGold: 10); weakGoblin.LootTable.AddDrop(lootSword, 1.0); var combat = new CombatEngine(display, input, new ControlledRandom()); var stats = new RunStats(); var result = combat.RunCombat(player, weakGoblin, stats); result.Should().Be(CombatResult.Won); player.HP.Should().BeGreaterThan(0); stats.EnemiesDefeated.Should().Be(1); player.Inventory.Should().Contain(i => i.Name == "Iron Sword"); player.Gold.Should().BeGreaterOrEqualTo(5); display.AllOutput.Should().Contain(s => s.Contains("combat")); display.AllOutput.Should().Contain(s => s.Contains("loot:")); }
    [Fact] public void FullGameLoop_PlayerDiesInCombat_CombatResultCorrect() { var display = new FakeDisplayService(); var input = new FakeInputReader("A", "A", "A"); var player = new Player { Name = "WeakHero", HP = 10, MaxHP = 10, Attack = 1, Defense = 0 }; var strongTroll = new Troll(); strongTroll.HP = 100; strongTroll.Attack = 50; var combat = new CombatEngine(display, input, new ControlledRandom()); var stats = new RunStats(); var result = combat.RunCombat(player, strongTroll, stats); result.Should().Be(CombatResult.PlayerDied); player.HP.Should().BeLessOrEqualTo(0); display.AllOutput.Should().Contain(s => s.Contains("combat")); }
    [Fact] public void FullGameLoop_StatusEffects_AppliedAndTracked() { var display = new FakeDisplayService(); var input = new FakeInputReader("A"); var player = new Player { Name = "Hero", HP = 100, MaxHP = 100, Attack = 50 }; var enemy = new Goblin(); enemy.HP = 1; enemy.Attack = 1; var statusMgr = new StatusEffectManager(display); statusMgr.Apply(enemy, StatusEffect.Poison, 3); var enemyHpBefore = enemy.HP; statusMgr.ProcessTurnStart(enemy); enemy.HP.Should().BeLessThan(enemyHpBefore); var combat = new CombatEngine(display, input, new ControlledRandom()); var stats = new RunStats(); var result = combat.RunCombat(player, enemy, stats); result.Should().Be(CombatResult.Won); display.AllOutput.Should().Contain(s => s.Contains("combat")); }
    [Fact] public void FullGameLoop_MassiveXPGain_TriggersMultipleLevelUps() { var display = new FakeDisplayService(); var input = new FakeInputReader("A", "1", "1"); var player = new Player { Name = "Hero", HP = 100, MaxHP = 100, Attack = 50 }; var initialLevel = player.Level; var enemy = new Goblin(); enemy.HP = 1; enemy.Attack = 1; enemy.XPValue = 250; var combat = new CombatEngine(display, input, new ControlledRandom()); var stats = new RunStats(); var result = combat.RunCombat(player, enemy, stats); result.Should().Be(CombatResult.Won); player.Level.Should().BeGreaterThan(initialLevel); player.XP.Should().Be(250); }
}
